149	export function slugifySkillId(text) {
150	  const normalized = text
151	    .toLowerCase()
152	    .replace(/客服/g, "customer_service")
153	    .replace(/质检/g, "qa")
154	    .replace(/政策/g, "policy")
155	    .replace(/合同/g, "contract")
156	    .replace(/会议/g, "meeting")
157	    .replace(/技能/g, "skill")
158	    .replace(/[^a-z0-9_-]+/g, "_")
159	    .replace(/^_+|_+$/g, "")
160	    .replace(/_+/g, "_");
161	  return (normalized || "generated_skill").slice(0, 64);
162	}
