164	export function createSkillFromNaturalLanguage(prompt) {
165	  const text = String(prompt || "").trim();
166	  const isQa = /质检|客服/.test(text);
167	  const isPolicy = /政策|条款|制度/.test(text);
168	  const isContract = /合同|风险|法务/.test(text);
169	  const name = isQa ? "客服质检助手" : isPolicy ? "政策问答 Skill" : isContract ? "合同风险审阅" : "业务流程助手";
170	  const skillId = slugifySkillId(`${name}_${Date.now().toString(36)}`);
171	  const output = isQa ? "score、issues、suggestions" : isPolicy ? "conclusion、reason、evidence、next_steps" : "conclusion、steps、risks、next_actions";
172	  return {
173	    id: `sk-${Date.now()}`,
174	    name,
175	    skillId,
176	    description: text || "基于自然语言描述生成的 Skill 草稿。",
177	    source: "在线编写",
178	    owner: "space",
179	    category: isQa ? "客服运营" : isPolicy ? "知识问答" : isContract ? "法务" : "业务流程",
180	    status: "草稿",
181	    version: "v0.1.0",
182	    creator: "jingxiu.zhao",
183	    updatedAt: "刚刚",
184	    agents: 0,
185	    assets: ["SKILL.md", "manifest.json", "input.schema.json", "output.schema.json", "examples/happy_path.md"],
186	    tags: ["生成", isQa ? "客服" : isPolicy ? "政策" : "流程"],
187	    scan: { level: "-", issues: 0, result: "未扫描", time: "-" },
188	    content: `/when_to_use
189	当用户的问题符合以下需求时使用：
190	- ${text || "需要按照明确流程处理业务任务"}
191	
192	/input
193	required:
194	  - user_query: 用户当前问题或任务目标
195	optional:
196	  - context: 对话上下文
197	missing_input_strategy: ask_user
198	
199	/output
200	format: markdown
201	structure:
202	  - ${output}
203	
204	/constraints
205	- 不得编造未在输入或参考资料中出现的信息
206	- 依据不足时必须明确说明需要补充信息
207	- 不得泄露用户隐私、平台内部数据或密钥凭证`
208	  };
