211	export function validateSkillId(skillId, existingIds = []) {
212	  const raw = String(skillId || "");
213	  if (raw.length < 3) return { valid: false, error: "技能标识至少 3 个字符" };
214	  if (raw.length > 64) return { valid: false, error: "技能标识不能超过 64 个字符" };
215	  if (!/^[a-z0-9_-]+$/.test(raw)) return { valid: false, error: "仅允许小写字母、数字、下划线和连字符" };
216	  if (existingIds.includes(raw)) return { valid: false, error: "技能标识已存在" };
217	  return { valid: true, error: "" };
218	}
