220	export function validatePublishReady(skill) {
221	  const content = String(skill.content || "");
222	  const required = ["/when_to_use", "/input", "/output", "/constraints"];
223	  const missing = required.filter(section => !content.includes(section));
224	  return { ready: missing.length === 0, missing };
225	}
