227	export function validateImportFile(filename, size) {
228	  const name = String(filename || "");
229	  const allowedExts = [".md", ".json", ".yaml", ".yml", ".zip"];
230	  const ext = name.slice(name.lastIndexOf(".")).toLowerCase();
231	  if (!ext || !allowedExts.includes(ext)) {
232	    return { valid: false, error: "仅支持 .md、.json、.yaml、.yml、.zip 格式" };
233	  }
234	  const maxSize = 10 * 1024 * 1024; // 10MB
235	  if (size > maxSize) {
236	    return { valid: false, error: "文件大小不能超过 10MB" };
237	  }
238	  const dangerousExts = [".exe", ".sh", ".bat", ".cmd", ".ps1", ".vbs", ".jar", ".py", ".rb"];
239	  if (dangerousExts.includes(ext)) {
240	    return { valid: false, error: "不允许上传可执行脚本或程序文件" };
241	  }
242	  return { valid: true, error: "" };
243	}
