309	export function getNextStatus(status, action) {
310	  const transitions = {
311	    "草稿:request_publish": "扫描中",
312	    "草稿变更:request_publish": "扫描中",
313	    "扫描失败:request_publish": "扫描中",
314	    "已下架:request_publish": "扫描中",
315	    "扫描中:scan_pass": "已发布",
316	    "扫描中:scan_fail": "扫描失败",
317	    "已发布:unpublish": "已下架"
318	  };
319	  const next = transitions[`${status}:${action}`];
320	  if (!next) throw new Error(`状态 ${status} 不允许执行 ${action}`);
321	  return next;
322	}
323	
324	export function filterSkills(skills, filters = {}) {
325	  const keyword = String(filters.keyword || "").trim().toLowerCase();
326	  return skills.filter(skill => {
327	    const inLibrary = filters.library === "official" ? skill.owner === "official" : skill.owner === "space";
328	    const matchesKeyword = !keyword || [skill.name, skill.skillId, skill.description, skill.category, ...(skill.tags || [])]
329	      .join(" ")
330	      .toLowerCase()
331	      .includes(keyword);
332	    const matchesStatus = !filters.status || filters.status === "全部" || skill.status === filters.status;
333	    const matchesSource = !filters.source || filters.source === "全部" || skill.source === filters.source;
334	    return inLibrary && matchesKeyword && matchesStatus && matchesSource;
335	  });
336	}
