36	test("validateSkillId rejects invalid inputs and accepts valid ones", () => {
37	  // too short
38	  assert.equal(validateSkillId("ab").valid, false);
39	  assert.ok(validateSkillId("ab").error);
40	  // too long
41	  assert.equal(validateSkillId("a".repeat(65)).valid, false);
42	  // invalid characters
43	  assert.equal(validateSkillId("Hello World").valid, false);
44	  assert.equal(validateSkillId("my_skill!").valid, false);
45	  assert.equal(validateSkillId("UPPERCASE").valid, false);
46	  // duplicate
47	  assert.equal(validateSkillId("customer_service_qa", ["customer_service_qa"]).valid, false);
48	  // valid
49	  assert.equal(validateSkillId("my_skill").valid, true);
50	  assert.equal(validateSkillId("valid-id-123").valid, true);
51	  assert.equal(validateSkillId("a0b").valid, true);
52	  assert.equal(validateSkillId("customer_service_qa", ["other_skill"]).valid, true);
53	});
