function filePreview(skill, fileName) {
  const content = skill.files?.[fileName] || "";
  if (fileName.endsWith(".md")) {
    if (fileName === "SKILL.md") {
      return renderSKILLPreview(skill, content);
    }
    return renderPlainMarkdown(content);
  }
  if (fileName.endsWith(".json")) {
    const formatted = tryFormatJSON(content);
    return `<div class="json-preview"><pre><code>${escapeHtml(formatted)}</code></pre></div>`;
  }
  return `<div class="text-preview"><pre>${escapeHtml(content)}</pre></div>`;
}

function renderSKILLPreview(skill, content) {
  const lines = String(content || "").split("\n");
  const html = lines.map(line => {
    if (line.startsWith("# ")) return `<h1>${escapeHtml(line.slice(2))}</h1>`;
    if (line.startsWith("## ")) return `<h2>${escapeHtml(line.slice(3))}</h2>`;
    if (/^\d+\.\s/.test(line)) return `<p class="ordered-line">${escapeHtml(line)}</p>`;
    if (line.startsWith("- ")) return `<p class="bullet-line">${escapeHtml(line.slice(2))}</p>`;
    if (!line.trim()) return "";
    return `<p>${escapeHtml(line)}</p>`;
  }).join("");
  return `
    <div class="rendered-skill">
      <h1>${escapeHtml(skill.name || "未命名技能")}</h1>
      <h2>技能说明</h2>
      <p>${escapeHtml(skill.description)}</p>
      ${html}
    </div>
  `;
}

function renderPlainMarkdown(content) {
  const lines = String(content || "").split("\n");
  const html = lines.map(line => {
    if (line.startsWith("# ")) return `<h1>${escapeHtml(line.slice(2))}</h1>`;
    if (line.startsWith("## ")) return `<h2>${escapeHtml(line.slice(3))}</h2>`;
    if (/^\d+\.\s/.test(line)) return `<p class="ordered-line">${escapeHtml(line)}</p>`;
    if (line.startsWith("- ")) return `<p class="bullet-line">${escapeHtml(line.slice(2))}</p>`;
    if (!line.trim()) return "";
    return `<p>${escapeHtml(line)}</p>`;
  }).join("");
  return `<div class="rendered-skill">${html}</div>`;
}

function tryFormatJSON(text) {
  try {
    return JSON.stringify(JSON.parse(text), null, 2);
  } catch {
    return text;
  }
}

function bundleFileTree(skill) {
  const files = skill.files || {};
