  const activeFile = state.activeFile || "SKILL.md";
  return `
    <div class="bundle-files">
      <header>
        <strong>Skill Bundle</strong>
        <span>${fileNames.length} 个文件</span>
      </header>
      <div class="bundle-tree">
        ${fileNames.map(name => {
          const content = files[name] || "";
          const deletable = name !== "SKILL.md";
          return `
            <div class="bundle-file-item${name === activeFile ? " active" : ""}">
              <span class="file-icon">${fileTypeIcon(name)}</span>
              <span class="file-name" title="${escapeAttr(name)}">${escapeHtml(name)}</span>
              <span class="file-size">${String(content).length}</span>
              ${deletable ? `<button type="button" class="file-delete-btn" data-delete-file="${escapeAttr(name)}" title="删除 ${escapeAttr(name)}">x</button>` : ""}
