.bundle-tree {
  display: grid;
  gap: 6px;
}

.bundle-file-item {
  display: grid;
  grid-template-columns: auto 1fr auto auto;
  align-items: center;
  gap: 6px;
  padding: 8px 10px;
  border: 1px solid var(--line);
  border-radius: var(--radius-sm);
  background: #fff;
  transition: border-color .16s;
}

.bundle-file-item.active {
  border-color: var(--blue);
  background: var(--blue-soft);
}

.bundle-file-item .file-icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 28px;
  height: 22px;
  border-radius: 4px;
  font-size: 10px;
  font-weight: 700;
  font-family: ui-monospace, SFMono-Regular, Menlo, monospace;
  background: var(--surface);
  color: var(--muted);
  flex-shrink: 0;
}

.bundle-file-item .file-name {
  font-family: ui-monospace, SFMono-Regular, Menlo, monospace;
  font-size: 12px;
  color: var(--text);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.bundle-file-item .file-size {
  font-size: 11px;
  color: var(--subtle);
  font-variant-numeric: tabular-nums;
}

.file-delete-btn {
  width: 24px;
  min-height: 24px;
  padding: 0;
  border: 0;
  border-radius: 4px;
  background: transparent;
  color: var(--muted);
  font-size: 14px;
  line-height: 1;
  display: grid;
  place-items: center;
  cursor: pointer;
  transition: color .12s, background .12s;
}

.file-delete-btn:hover {
  color: var(--red);
  background: #fff1f2;
}

.add-file-btn {
  width: 100%;
  min-height: 34px;
  border: 1px dashed var(--line);
  border-radius: var(--radius-sm);
  background: transparent;
  color: var(--blue);
  font-size: 13px;
  cursor: pointer;
  transition: border-color .16s, background .16s;
  margin-top: 6px;
}

.add-file-btn:hover {
  border-color: var(--blue);
  background: var(--blue-soft);
}

.json-preview {
  border-radius: var(--radius-sm);
  overflow: auto;
  background: #111827;
}

.json-preview pre {
  max-height: none;
  background: transparent;
  color: #e5e7eb;
}

.text-preview pre {
  max-height: none;
